+    #[test]
+    fn parse_dim() {
+        let text = parse_markup("[dim]Faded[/dim]").unwrap();
+        assert_eq!(text.to_plain_text(), "Faded");
+        let style = text.lines()[0].spans()[0].style.unwrap();
+        assert!(style.has_attr(StyleFlags::DIM));
+    }
